  ('fire-eq-tech-moex-02130', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準裝置水霧滅火設備之室內停車空間，其排水設備應符合下列何者規定？', '["車輛停駐場所地面作百分之五以上之坡度", "在車道之中央或二側應設置排水溝，排水溝設置集水管，並與滅火坑相連接", "車輛停駐場所，都應設高十公分以上之地區境界堤，或深十公分寬十公分以上之地區境界溝，並與排 水溝連通", "滅火坑可不設油水分離裝置，但需設於火災不易殃及之處所"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
